{action_set_definitions}: {
  "get_permissions": {
    "description": "Retrieves the current user's access level to determine if they can view sensitive documents or modify logs.",
    "parameters": {
      "type": "object",
      "properties": {},
      "required": []
    },
    "example_output": {
      "access_level": "Admin"
    }
  },
  "list_documents": {
    "description": "Retrieves metadata for all documents in the data room, used to identify contract IDs and titles.",
    "parameters": {
      "type": "object",
      "properties": {},
      "required": []
    },
    "example_output": {
      "documents": [
        {
          "id": "DOC-001",
          "title": "ChipCo Master Supply Agreement",
          "type": "Contract",
          "status": "Final"
        }
      ]
    }
  },
  "get_review_checklist": {
    "description": "Queries the current completion status of the due diligence checklist categories.",
    "parameters": {
      "type": "object",
      "properties": {},
      "required": []
    },
    "example_output": {
      "checklist": {
        "Supply_Chain_Resilience": "Pending",
        "M&A_Compliance": "Pending"
      }
    }
  },
  "open_document": {
    "description": "Sets the active_document_id to the specified document to allow for content searching.",
    "parameters": {
      "type": "object",
      "properties": {
        "document_id": {
          "type": "string",
          "description": "The unique ID of the document to open."
        }
      },
      "required": [
