      ]
    },
    "example_output": {
      "status": "success",
      "active_document_id": "DOC-001"
    }
  },
  "search_document_content": {
    "description": "Searches the currently active document for specific keywords or clauses.",
    "parameters": {
      "type": "object",
      "properties": {
        "keywords": {
          "type": "array",
          "items": {
            "type": "string"
          },
          "description": "Keywords to search for, e.g., ['Force Majeure', 'Allocation']."
        }
      },
      "required": [
        "keywords"
      ]
    },
    "example_output": {
      "matches": [
        {
          "keyword": "Force Majeure",
          "excerpt": "In the event of Force Majeure, ChipCo reserves the right to allocate..."
        }
      ]
    }
  },
  "log_risk": {
    "description": "Logs an identified risk into the environment state, including severity and description.",
    "parameters": {
      "type": "object",
      "properties": {
        "document_id": {
          "type": "string",
          "description": "ID of the document associated with the risk."
        },
        "risk_type": {
          "type": "string",
          "description": "The name of the risk (e.g., 'Supply Gap Risk')."
        },
        "description": {
          "type": "string",
          "description": "Detailed explanation of why this is a risk based on the clause analysis."
        },
        "severity": {
          "type": "string",
          "enum": [
            "Low",
            "Medium",
            "High",
            "Critical"
          ],
          "description": "The risk level assessed."
        }
      },
      "required": [
        "document_id",
        "risk_type",
        "description",
        "severity"
      ]
    },
    "example_output": {
      "status": "logged"
    }
  },
  "update_checklist_status": {
    "description": "Updates the completion status of a specific category in the review checklist.",
    "parameters": {
      "type": "object",
      "properties": {
        "category": {
          "type": "string",
          "description": "The checklist category to update (e.g., 'Supply_Chain_Resilience')."
        },
        "status": {
          "type": "string",
          "description": "The new status value (e.g., 'Completed')."
        }
      },
      "required": [
        "category",
        "status"
      ]
    },
    "example_output": {
      "status": "updated"
    }
  }
}
